"""
MKT Original Commentary — Job chapters 33–35
Run: python3 scripts/zc-original-job-33-35.py

Elihu's speeches to Job (ch33) and the wise men (ch34), then back to Job (ch35).
Key decisions:
- meliṣ (33:23): rendered "mediator/messenger" — the most significant mediator-term outside ch19 gōʾēl
- kōper (33:24): "ransom" — soteriological weight preserved; NOT "atonement" (too narrowly cultic)
- ḥālîlāh (34:10): "far be it from God" — standard protest formula; preserved as idiom
- rûḥô wᵉnišmāṯô (34:14): "spirit and breath" — both terms retained; cosmic breath sustaining life
- šaḥaṯ (33:18, 22, 24, 28, 30): "the pit" — consistently rendered; Elihu uses it more than any speaker
- ʾayyēh ʾĕlôhay ʿōśênî (35:10): "Where is God my Maker" — the nocturnal praise phrase; critical for Elihu's transcendence argument
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "33": {
    "1": "<p>&#8220;But now, Job, hear my words.&#8221; Elihu addresses Job directly for the first time after his long preamble in ch32. The <em>wᵉʾûlām</em> (but now) marks the transition from introduction to argument — Elihu has established his right to speak; now he will speak to the one the Friends could not answer. The invitation to <em>šimʿ</em> (hear/listen) mirrors the wisdom-instruction formula of Proverbs (e.g., Prov 4:1) — Elihu frames himself as a teacher, not a prosecutor.</p>",
    "2": "<p>&#8220;I have opened my mouth; my tongue speaks within my mouth.&#8221; The doubled description of speech-preparation — <em>pāṯaḥtî pî</em> (I have opened my mouth) and <em>dibbᵉrāh lᵉšônî bᵉḥikkî</em> (my tongue speaks within my palate) — is ceremonial, like a herald announcing official speech. Elihu is young; the formality is deliberate self-presentation. The MKT preserves both phrases rather than collapsing them, because the redundancy is itself meaningful: Elihu is performing the act of authoritative address.</p>",
    "3": "<p>&#8220;My words come from an upright heart; my lips speak what I know sincerely.&#8221; <em>Yōšer-libbî</em> (uprightness of my heart) and <em>ḏaʿaṯ śᵉpātay bārûr</em> (pure knowledge my lips speak) — Elihu claims both moral and epistemic integrity. The term <em>bārûr</em> (pure, clear) is a metallurgical term: smelted free of impurity. He distinguishes his speech from the Friends&#8217; by asserting that he has not composed arguments to fit a position; the MKT&#8217;s &#8220;sincerely&#8221; captures the <em>bārûr</em> quality without the metallurgical image, which English would overload.</p>",
    "4": "<p>&#8220;The Spirit of God has made me, and the breath of the Almighty gives me life.&#8221; <em>Rûaḥ-ʾēl</em> (Spirit of God) and <em>nišmaṯ šaddai</em> (breath of the Almighty) are paired as the source of Elihu&#8217;s life — an echo of Gen 2:7 (<em>nišmaṯ ḥayyîm</em>) and Job 12:10. Elihu grounds his authority not in age (like the Friends) but in the same divine breath that gave life to Adam. This prepares his argument that his speech participates in what God says through creatures. The MKT renders both nouns distinctly (Spirit/breath) to preserve the parallelism.</p>",
    "5": "<p>&#8220;If you can answer me, set your words in order before me and take your stand.&#8221; <em>ʿᵃrāḵāh</em> (set in order, marshal) is a legal-military term — the same root as &#8220;draw up in battle array&#8221; (cf. Job 6:4). Elihu invites Job to the same forensic contest Job has demanded of God throughout the dialogue (9:14-15; 13:18; 23:4). The difference is that Elihu is a human being, not God — Job has no reason to be afraid of him (v7). The irony is that Elihu is attempting to do what Job&#8217;s <em>môkîaḥ</em> (umpire, 9:33) was supposed to do.</p>",
    "6": "<p>&#8220;I too was formed from clay.&#8221; <em>Qōreṣtî</em> (I was pinched off, formed) from <em>ḥōmer</em> (clay) — the same word-pair as 10:9 (&#8220;You formed me like clay&#8221;). Elihu claims creaturely solidarity with Job: both are clay-formed; neither can claim intrinsic advantage before God. The phrase <em>gam-ʾᵃnî kᵉpiḵā</em> (I too am like you) is a deliberate leveling gesture, undermining the Friends&#8217; implicit superiority. The MKT &#8220;formed from clay&#8221; preserves both the humility claim and the creation-theology subtext.</p>",
    "7": "<p>&#8220;My dread will not terrify you, nor will my pressure be heavy upon you.&#8221; Elihu explicitly contrasts himself with God: Job has complained that God&#8217;s <em>ʾêmāh</em> (terror/dread) makes a fair hearing impossible (9:34; 13:21). The <em>ʾakkᵉḵā</em> (my pressure upon you) uses the same weight-imagery as 23:2 (<em>ʾânāḵāh</em> — my complaint is heavier than groaning). Elihu is a human mediator who can engage without the ontological terror that makes Job&#8217;s encounter with God so fraught. He is, in effect, claiming to be the safe interlocutor Job longed for.</p>",
    "8": "<p>&#8220;You have spoken in my hearing.&#8221; <em>Bᵉʾoznay</em> (in my ears) — Elihu claims to have heard all of Job&#8217;s speeches firsthand. Vv8-11 are his summary of what Job said: a three-fold claim of innocence followed by a claim that God is Job&#8217;s enemy. The accuracy of the summary is significant: unlike the Friends who distorted Job&#8217;s words (e.g., Eliphaz in 22:6-9), Elihu quotes Job with reasonable precision. This is part of Elihu&#8217;s rhetorical self-presentation as a fair witness.</p>",
    "9": "<p>&#8220;You said: &#8216;I am clean, without transgression; I am innocent and there is no iniquity in me.&#8217;&#8221; <em>Zak</em> (pure, clean) and <em>ḥattāʾṯ</em> (transgression/sin) — Elihu&#8217;s summary of Job&#8217;s self-defense. Job has indeed claimed moral integrity throughout (6:30; 9:21; 23:10; 27:5-6). The key term <em>ḥāpēš pešāʿ</em> (without transgression) uses <em>pešaʿ</em>, the term for deliberate, willful rebellion — not accidental sin. Job&#8217;s claim is strong: he has not deliberately rejected God. Elihu will not contest this directly but will reframe the question.</p>",
    "10": "<p>&#8220;But you also said: &#8216;He finds grievances against me; he regards me as his enemy.&#8217;&#8221; <em>Tᵉnûʾôṯ</em> (grievances, occasions against me) — the term suggests manufactured pretexts: God is not responding to real evidence but inventing reasons for hostility. <em>ʾôyēḇ</em> (enemy) is Job&#8217;s sharpest charge against God (13:24; 16:9; 19:11). Elihu is accurate that this is what Job said. His upcoming argument will not deny that Job suffers, but will contest the interpretation: God-as-enemy is wrong; God speaks through suffering (<em>for</em> Job, not against him).</p>",
    "11": "<p>&#8220;He puts my feet in stocks; he watches all my paths.&#8221; <em>Sāḏ</em> (stocks/fetters) from 13:27 — Job&#8217;s complaint that God treats him as a prisoner under surveillance. <em>Yišmōr</em> (watches) carries the double sense of guarding/protecting and monitoring/spying; Job experiences God&#8217;s watch as hostile (<em>ṣāpan lî</em>, &#8220;watching over me for evil,&#8221; 10:14). Elihu is re-quoting Job&#8217;s words to set up the correction: the divine watch is not punitive surveillance but providential shepherding of a creature toward its own good.</p>",
    "12": "<p>&#8220;But in this I tell you plainly that you are wrong: God is greater than any human being.&#8221; <em>Lōʾ-ṣāḏaqtā</em> (you are not right/you are wrong) — Elihu&#8217;s direct verdict on Job&#8217;s position. The reason given is <em>yirbaʿ ʾĕlôah mimmenneš</em> (God is greater than any human being): God&#8217;s transcendence means the creature cannot set the terms of the relationship. This is partially right — the whirlwind speeches will make the same point (38:4). But Elihu&#8217;s version lacks the personal engagement God brings; he argues from category rather than relationship.</p>",
    "13": "<p>&#8220;Why do you argue against him? For he does not give account for any of his actions.&#8221; <em>Lōʾ-yᵃʿᵃneh ʿal-kol-dᵉḇārāyw</em> (he does not answer for all his actions) — the divine non-accountability argument. This is Elihu&#8217;s strongest argument and his weakest: it is strong because it is true (God does not owe answers to creatures) but weak because it does not address why Job should trust a God who acts unaccountably. Elihu will partly answer this in vv14-30 by showing that God does communicate — through dreams and suffering.</p>",
    "14": "<p>&#8220;For God speaks in one way and then another, though people do not notice.&#8221; <em>Bᵉʾaḥaṯ</em> (in one way) and <em>bišᵉtayim</em> (in two/another) — the MKT&#8217;s &#8220;in one way and then another&#8221; captures the numerical idiom. The critical term is <em>lōʾ yᵉšûrennāh</em> (people do not perceive/notice it): the problem is not that God is silent but that human perception is inadequate. This reframes Job&#8217;s complaint from divine absence to human obtuseness — a partial but real answer to Job&#8217;s cry that God &#8220;hides his face&#8221; (13:24).</p>",
    "15": "<p>&#8220;In a dream, in a nighttime vision, when deep sleep falls on people as they slumber on their beds.&#8221; <em>Bᵉḥēzôn laylāh</em> (nighttime vision) and <em>tardēmāh</em> (deep sleep) — the term <em>tardēmāh</em> is significant: it is the same word used for Adam&#8217;s deep sleep in Gen 2:21 and Abram&#8217;s in Gen 15:12 (where God cuts the covenant). The nocturnal divine communication channel Elihu describes is not peripheral but central to OT covenant experience. Job has received no such visions; his nights are torment (7:14). Elihu&#8217;s point: God uses this channel; Job should attend to it.</p>",
    "16": "<p>&#8220;He opens people&#8217;s ears and confirms what he is teaching them.&#8221; <em>Yigleh ʾōzen</em> (opens/uncovers the ear) — the idiom means to whisper into someone&#8217;s ear; more literally, to remove the covering so hearing is possible. God is not broadcasting into static; he is preparing the ear. <em>Wᵉbᵉmōsārām yaḥtōm</em> (and in their correction he seals) — the &#8220;seals&#8221; here means confirms/impresses: God does not just communicate but ensures the message is received. This is the theology of divine perseverance in communication that Elihu presents against Job&#8217;s experience of silence.</p>",
    "17": "<p>&#8220;To turn them from their intended course and shield them from pride.&#8221; <em>Lᵉhāsîr ʾāḏām mᵃʿᵃśeh</em> (to turn a man from his deed/course) and <em>gēwāh</em> (pride) — the purpose of divine night-communication is redirective: away from a self-destructive course, away from pride. This echoes the wisdom literature&#8217;s consistent association of <em>gēwāh</em>/<em>gāʾôn</em> (pride) with the path to <em>šaḥaṯ</em> (destruction/pit). God disciplines not to punish but to redirect before the person reaches the edge. This is Elihu&#8217;s most generous interpretation of suffering.</p>",
    "18": "<p>&#8220;He keeps him from the pit and his life from crossing into death.&#8221; <em>Šaḥaṯ</em> (the pit) — Elihu&#8217;s first use of his key term; he will use it six more times in vv22-30. The pit is not just a metaphor for death but the place of permanent darkness below; <em>šelaḥ</em> (sword/weapon; or canal/channel) in some traditions is the name of a river crossing into death. The MKT &#8220;crossing into death&#8221; captures the spatial imagery: a threshold not to cross. God&#8217;s nocturnal discipline is pre-emptive preservation — keeping the person from arriving at the pit.</p>",
    "19": "<p>&#8220;He is also chastened with pain upon his bed, and with unending conflict in his bones.&#8221; <em>Yûkāḥ</em> (he is chastened/disciplined) from <em>yākaḥ</em> — the same root as Job&#8217;s longed-for <em>môkîaḥ</em> (umpire, 9:33). The suffering Elihu describes is disciplinary: <em>kᵉʾēḇ</em> (pain) on the bed and <em>rîb ʿᵃṣāmāyw</em> (strife/conflict of his bones) — inward physical suffering. Elihu&#8217;s framework exactly describes Job&#8217;s condition: Job is on his bed, in bone-pain. The implication — which Job resists — is that Job&#8217;s suffering is of this disciplinary type.</p>",
    "20": "<p>&#8220;So that he cannot eat bread and his appetite revolts against any food.&#8221; <em>Zihhᵃmāṯtᵉhû</em> (it loathes) describes nausea that makes even the smell of food repulsive. This is a clinical description of severe illness: appetite failure is among the last symptoms before death in ancient understanding (cf. 6:7). Elihu is particularizing the suffering: not vague distress but the specific loss of appetite that marks near-fatal illness. Job&#8217;s body has done exactly this (3:20-22; 7:5). The purpose-clause framing (&#8220;so that&#8221; — this illness serves the goal of vv17-18) is Elihu&#8217;s interpretive move.</p>",
    "21": "<p>&#8220;His flesh wastes away until it is gone, and his bones that were hidden now protrude.&#8221; <em>Kālāh ḇāśār</em> (his flesh wastes/finishes) and <em>šupî ʿᵃṣāmôṯāyw</em> (his bones that were hidden/unseen) — the progression from appetite-loss to visible skeletal wasting. The bones &#8220;that were not seen&#8221; now protrude: this is the precise symptom Job displays in 19:20 (&#8220;my bones cling to my skin and to my flesh&#8221;). Elihu&#8217;s medical description applies to Job in real time while he speaks. The listener is meant to recognize: this is what is happening to Job, and it has redemptive purpose.</p>",
    "22": "<p>&#8220;His life draws near the pit and his soul to the agents of death.&#8221; <em>Šaḥaṯ</em> (the pit) appears again; <em>mᵉmîtîm</em> (agents of death) — possibly &#8220;those who kill&#8221; or death-messengers (LXX: &#8220;in death&#8221;). This is the nadir of the suffering arc Elihu describes: the person has arrived at the brink of the pit. But the very extremity sets up the intervention of v23. Elihu structures his theodicy as a drama: suffering serves a purpose up to the very edge of the pit; then God intervenes through the mediator. Job is at exactly this edge.</p>",
    "23": "<p>&#8220;But if there is a messenger for him, a mediator — one in a thousand.&#8221; <em>Meliṣ</em> (interpreter/mediator/messenger) is the pivotal term in Job 33 and among the most significant in the OT wisdom tradition. The root <em>lûṣ</em> means to interpret, translate, or intercede between parties. <em>ʾeḥāḏ minnî-ʾālep</em> (one from a thousand) conveys extreme rarity — not impossible but profoundly uncommon. This figure <em>lᵉhaggîḏ lāʾāḏām yōšrô</em> (declares to the person what is right for him) — functions exactly as Job&#8217;s <em>môkîaḥ</em> (9:33) and <em>gōʾēl</em> (19:25): a being who mediates between the dying person and God to declare what is actually the person&#8217;s <em>yōšer</em> (uprightness/right path). Unlike Job&#8217;s mediator-hope, Elihu&#8217;s <em>meliṣ</em> appears to already exist within God&#8217;s provision — the question is whether the sufferer has one.</p>",
    "24": "<p>&#8220;Then God is gracious to him and says: Spare him from going down to the pit; I have found a ransom.&#8221; <em>Wayyeḥunnenû</em> (and he is gracious to him) — divine <em>ḥēn</em> (grace) is the operative force. God&#8217;s verdict is <em>pᵉḏêhû mēreḏeṯ šaḥaṯ</em> (spare/ransom him from descending to the pit). <em>Kōper</em> (ransom) is the most loaded term in the verse: in cultic law, the <em>kōper</em> is the substitutionary payment that covers a liability (Exod 30:12; Num 35:31-32). Here God himself <em>māṣāʾtî kōper</em> (I have found a ransom) — the ransom is not provided by the human being but discovered/provided by God. The structure anticipates the NT: the ransom for human life before the pit is not earned but given. The MKT &#8220;I have found a ransom&#8221; preserves the first-person divine speech embedded here.</p>",
    "25": "<p>&#8220;His flesh becomes fresher than a child&#8217;s; he is restored to the days of his youth.&#8221; <em>Raṭap</em> (fresh, supple) — used only here in the OT; the root suggests glistening moisture. <em>Yāšôb lîmê ʿᵃlûmāyw</em> (he returns to the days of his youth) — the restoration is not merely physical survival but renewal to the vitality of youth. This is hyperbolic but theologically serious: God&#8217;s ransom restores to a state prior to the destruction. In the book&#8217;s narrative arc, Job himself will experience this restoration (42:10-17). Elihu&#8217;s theology of the pit-ransom is, in structure, correct — even if his application to Job misreads Job&#8217;s specific situation.</p>",
    "26": "<p>&#8220;He prays to God and God accepts him; he sees his face with a shout of joy, and God restores his righteousness.&#8221; <em>Yiṣʿaq</em> (he cries out/prays) and <em>yirṣēhû</em> (God accepts him) — the sequence: prayer → acceptance → face-vision → righteousness restored. <em>Yirāʾeh pānāyw</em> (he sees God&#8217;s face) is the language of restored relationship and throne-room access (cf. Ps 17:15; 11:7). <em>Wayyāšeḇ lᵉʾenôš ṣiḏqāṯô</em> (he restores to the person his righteousness) — God gives back what suffering temporarily took. This is the full restoration arc: ransom (v24) → physical renewal (v25) → restored communion and righteousness (v26).</p>",
    "27": "<p>&#8220;He looks on people, and if any say: &#8216;I sinned and bent what was right, and it brought me nothing good.&#8217;&#8221; <em>Yāšōr ʿal-ʾᵃnāšîm</em> (he looks on/surveys people) — the restored person becomes a witness-testimony to others. The confession cited — <em>ḥāṭāʾtî wᵉyāšār hiʿwêṯî</em> (I sinned and perverted what was right) — is exactly what the Friends demanded of Job throughout the dialogue. But note the sequence here: the confession comes <em>after</em> the ransom and restoration, not as the precondition. The confession is the fruit of deliverance, not its cause. This subtly subverts the Friends&#8217; theology while using their vocabulary.</p>",
    "28": "<p>&#8220;God will deliver his life from the pit, and his life will see the light.&#8221; <em>Pāḏāh napšô mᵉʿᵃḇōr baššaḥaṯ</em> (redeemed his life from crossing into the pit) — <em>pāḏāh</em> (redeem, ransom) is closely related to <em>kōper</em> in v24; both words denote the act of paying the price that releases someone from a claim. <em>Ḥayyāyw bāʾôr tirʾeh</em> (his life will see the light) — the light-versus-pit contrast that runs through the whole speech reaches its climax: the person who was at the edge of the pit now stands in the light of life. The <em>ôr ḥayyîm</em> (light of the living, v30) is the antithesis of the pit-darkness.</p>",
    "29": "<p>&#8220;See, God does all these things — again and again — with a person.&#8221; <em>Kol-ʾēlleh yiṣʿ-ʾēl pᵉʿāmayim šālôš</em> (two times, three times) — the graded numerical formula (twice/thrice) is the biblical idiom for &#8220;repeatedly, persistently.&#8221; God is not a single-intervention deity; he does the dream-warning, suffering-chastening, mediator-ransom cycle not once but as many times as needed. This responds to Job&#8217;s implicit complaint that God has abandoned him: Elihu insists God perseveres in reaching the human creature. The <em>ʿim-gāḇer</em> (with a man/person) keeps the register human and relational rather than cosmological.</p>",
    "30": "<p>&#8220;To bring his life back from the pit, that he might be lit by the light of the living.&#8221; <em>Lᵉhāšîḇ napšô</em> (to bring back his life/soul) and <em>ʾôr bᵉʾôr haḥayyîm</em> (light, in the light of the living) — the repetition of <em>ʾôr</em> (light) is emphatic. The purpose of everything Elihu has described — dreams, suffering, mediator, ransom — is this: that the human being lives in the light of the living rather than descending into the pit. This is Elihu&#8217;s theology of providence: every divine act toward the creature is ultimately directional — toward life, light, face-to-face restoration. It is the right theology; whether it applies to Job&#8217;s situation in the way Elihu implies is another question.</p>",
    "31": "<p>&#8220;Pay close attention, Job; listen to me; be silent and I will speak.&#8221; Elihu&#8217;s rhetorical instruction to Job after the theological display of vv14-30. <em>Qᵉšāḇ-lî Iyyôḇ</em> (pay attention to me, Job) — direct address. The double imperative <em>šimʿ-lî hašqeṯ wᵉʾānōḵî ʾᵃḏabbēr</em> (listen, be silent, and I will speak) mirrors the structure of teacher-to-student in wisdom literature. Elihu is trying to get Job into the posture of a learner, the posture the Friends&#8217; bullying never achieved. The invitation is genuine; whether Job can receive it is the question the narrative leaves open.</p>",
    "32": "<p>&#8220;If you have anything to say, answer me; speak up, for I want to see you vindicated.&#8221; <em>Ḥāpaṣtî ṣidqeḵā</em> (I desire/want your vindication/righteousness) — Elihu makes an extraordinary claim: he is on Job&#8217;s side. He wants Job to be vindicated, not condemned. This is different from the Friends, who want Job to confess guilt so the theodicy holds. Elihu believes Job&#8217;s integrity is real (32:3 — the Friends were wrong to condemn Job) but that Job&#8217;s interpretation of his situation is wrong. He is attempting to do what the <em>môkîaḥ</em> (umpire) would do: hold the space for both God&#8217;s righteousness and Job&#8217;s vindication.</p>",
    "33": "<p>&#8220;If not, listen to me; be silent, and I will teach you wisdom.&#8221; <em>ḥoḵmāh</em> (wisdom) — the speech ends with Elihu&#8217;s stated goal: wisdom, not Job&#8217;s defeat. The conditional structure (if you answer / if you don&#8217;t) offers Job genuine agency. The final word <em>ḥoḵmāh</em> is the book&#8217;s supreme value, last invoked in 28:28 (the fear of the Lord is wisdom; departure from evil is understanding). Elihu is positioning his speech as wisdom-teaching rather than prosecution. Whether he delivers on this claim is the interpretive challenge of chs33-37.</p>"
  },
  "34": {
    "1": "<p>&#8220;Elihu answered and said.&#8221; The formulaic speech-introduction marks the transition from Elihu&#8217;s address to Job (ch33) to his address to the wider company of wise men (v2). The dialogic structure of Job has always included an implicit audience beyond the immediate interlocutors; Elihu makes this explicit by appealing to ḥᵃkāmîm (wise men) and yōḏᵉʿîm (those who know/men of knowledge). He is placing his argument before a court of the wise — a move that both elevates the argument and implicitly invites the wise men to judge whether Job or Elihu is right.</p>",
    "2": "<p>&#8220;Hear my words, O wise men; listen to me, you who have knowledge.&#8221; <em>Ḥᵃkāmîm</em> (wise men) and <em>yōḏᵉʿîm</em> (those who know) — Elihu addresses the same audience the Friends implicitly spoke to throughout. The doubling of the invitation (hear/listen) is the standard wisdom-call of Proverbs (Prov 1:8; 4:10; 8:32-34). By addressing the wise men rather than Job, Elihu shifts register: this speech is less a personal confrontation than a public theological demonstration. The question at stake is whether God can act unjustly — and what wisdom tradition says about it.</p>",
    "3": "<p>&#8220;For the ear tests words as the palate tastes food.&#8221; <em>Ḥēk yiṭʿam-ʾōkel</em> (the palate tastes food) — the taste-wisdom metaphor recalls 12:11 where Job himself used it (&#8220;Does not the ear test words as the palate tastes food?&#8221;). Elihu may be consciously echoing Job&#8217;s own epistemology: discernment comes through careful testing, not reflexive judgment. The audience of wise men is being invited to taste Elihu&#8217;s argument as one tastes a complex dish — to evaluate it through experienced discernment rather than surface reaction. He is appealing to the wisdom tradition&#8217;s own self-understanding.</p>",
    "4": "<p>&#8220;Let us choose together what is right; let us determine among ourselves what is good.&#8221; <em>Nibḥᵃrāh-lānû mišpāṭ</em> (let us choose for ourselves justice/what is right) — the language is deliberative and communal: <em>nibḥᵃrāh</em> (let us choose, hortatory) and <em>nēḏᵉʿāh</em> (let us know/determine). Elihu frames the discussion as a shared inquiry rather than a tribunal. The <em>bōn ʾêleymô mah-ṭôḇ</em> (let us recognize among ourselves what is good) brings the wisdom criterion (<em>ṭôḇ</em>, good) alongside the legal criterion (<em>mišpāṭ</em>, justice). This is Elihu at his most collegial — and rhetorically careful: he is not yet pronouncing but inviting shared judgment.</p>",
    "5": "<p>&#8220;For Job has said, &#8216;I am righteous, and God has denied me my right.&#8217;&#8221; <em>Ṣāḏaqtî</em> (I am righteous) and <em>ʾēl hēsîr mišpāṭî</em> (God has removed/denied my right) — Elihu&#8217;s summary of Job&#8217;s central complaint. Job has indeed said both (27:2: &#8220;As God lives, who has denied me justice&#8221;; 31:35: &#8220;let the Almighty answer me&#8221;). The juxtaposition of Job&#8217;s self-declared righteousness and God&#8217;s denial of his right is the core tension of the book. Elihu will argue that this juxtaposition involves a category error: God cannot deny justice because God is the source and definition of justice.</p>",
    "6": "<p>&#8220;Must I lie about my case? My wound is past healing, though I have done no wrong.&#8221; This is quoted speech — either Elihu&#8217;s continuation of Job&#8217;s words or his own exclamation. <em>Hᵃʿal-mišpāṭî ʾᵃḵazzēḇ</em> (must I lie about my judgment/case?) — the rhetorical question expresses the dilemma: if God is just and Job suffers, either Job lied about his innocence or God is unjust. <em>Ḥiṣṣî</em> (my wound/arrow) — the &#8220;arrow&#8221; image for suffering echoes 6:4 (the arrows of the Almighty). Job&#8217;s complaint is presented at its sharpest before Elihu refutes it.</p>",
    "7": "<p>&#8220;What man is like Job, who drinks mockery like water?&#8221; <em>Yišteh-laʿag kayyāyin</em> (drinks mockery like water) — <em>laʿag</em> (mockery, scorn) as a beverage is a striking metaphor: Job consumes criticism so easily and continuously that it has become his drink. The comparison sharpens in v8: drinking mockery is associated with keeping company with evildoers. Elihu is beginning his critique: Job&#8217;s rhetoric has gone so far in accusing God that it amounts to companionship with the wicked. The &#8220;water&#8221; comparison contrasts with Job&#8217;s thirst for vindication (19:7; 30:20).</p>",
    "8": "<p>&#8220;Who keeps company with evildoers and walks with wicked men.&#8221; <em>ʿᵃrāḇāh</em> (pledges/associates with) and <em>pōʿᵃlê ʾāwen</em> (workers of iniquity) — Elihu accuses Job of rhetorical solidarity with the wicked: by claiming God acts arbitrarily, Job argues what the wicked claim (Ps 10:4; 14:1). <em>Lāleḵeṯ ʿim-ʾanšê rešaʿ</em> (to walk with wicked men) — the &#8220;walking&#8221; language picks up Ps 1:1. Elihu is not claiming Job is personally wicked; he is claiming Job&#8217;s theological argument, if correct, would make the wicked&#8217;s worldview right. This is a logical rather than moral charge.</p>",
    "9": "<p>&#8220;For he has said, &#8216;A man gains nothing by delighting in God.&#8217;&#8221; <em>Lōʾ-yiskōn geḇer birṣōṯô ʿim-ʾĕlôhîm</em> (a man gains nothing by his delight/favor with God) — this is Elihu&#8217;s most extreme summary of Job&#8217;s position, and it is a distortion. Job never said this directly; the closest is 21:15 (&#8220;What is the Almighty that we should serve him? What do we gain by praying to him?&#8221; — which is quoted speech of the wicked). Elihu has conflated Job&#8217;s complaint about God&#8217;s injustice with the wicked&#8217;s rejection of God entirely. This is an unfair characterization, which the divine verdict of 42:7-8 will implicitly correct.</p>",
    "10": "<p>&#8220;Therefore, men of understanding, listen to me: far be it from God to do evil, far from the Almighty to commit wrong.&#8221; <em>Ḥālîlāh lāʾēl mērāšaʿ</em> (far be it from God to do wrong) and <em>wᵉšaddai mēʿāwel</em> (and from the Almighty to do iniquity) — the <em>ḥālîlāh</em> formula is a strong rhetorical protest (cf. Gen 18:25, Abraham&#8217;s &#8220;far be it from you&#8221;; 1 Sam 12:23; Rom 6:1-2). This is the core of Elihu&#8217;s theodicy: God&#8217;s character is the argument. Not &#8220;God&#8217;s ways are too complex to understand&#8221; but &#8220;God cannot be other than just because <em>rāšaʿ</em> (wickedness) is definitionally incompatible with who God is.&#8221; This is stronger than the Friends&#8217; retributive theodicy and anticipates the divine speeches.</p>",
    "11": "<p>&#8220;For he repays each person according to their work and deals with everyone according to their conduct.&#8221; <em>Kî pōʿal ʾāḏām yᵉšallemnî-lô</em> (for the work of a man he will repay him) — the retributive principle that the Friends also affirm, but Elihu uses it differently: not as accusation against Job but as proof of God&#8217;s justice-character. If God repays each according to work, then God is just by definition. The verse does not explain why Job suffers specifically; it establishes the framework within which the specific question must be asked. Elihu&#8217;s argument is structurally consistent even if it does not answer Job&#8217;s specific complaint.</p>",
    "12": "<p>&#8220;Of a truth, God will not act wickedly; the Almighty will not pervert justice.&#8221; <em>ʾAp-ʾomnam ʾēl lōʾ-yarešîaʿ</em> (truly, God will not act wickedly) — the <em>ʾap-ʾomnam</em> (surely, truly) is emphatic: Elihu is staking his argument on the impossibility of divine injustice. <em>Yᵉʿawwēt mišpāṭ</em> (pervert/distort justice) uses the <em>ʿwt</em> root that appeared in 8:3 (Bildad: &#8220;Does God pervert justice?&#8221;) — now Elihu gives a direct answer: no. The impossibility of God&#8217;s perverting justice is not a logical axiom but a theological claim about God&#8217;s character as Creator and sustainer.</p>",
    "13": "<p>&#8220;Who gave him his charge over the earth? Who appointed him over the whole world?&#8221; <em>Mî-pāqaḏ ʿālāyw ʾāreṣ</em> (who appointed him over the earth?) — the rhetorical questions expect the answer &#8220;no one.&#8221; God is not an appointed magistrate who could be removed or judged by a higher authority; God&#8217;s sovereignty is inherent, not delegated. This argument from ontology undergirds the claim of v10: God cannot be unjust because there is no external standard of justice above God to which God is answerable. This is Elihu&#8217;s most philosophically sophisticated point, and it anticipates the whirlwind speeches&#8217; argument from creatorial incomparability.</p>",
    "14": "<p>&#8220;If he should set his heart against us and gather to himself his Spirit and breath.&#8221; <em>Rûḥô wᵉnišmāṯô</em> (his Spirit and his breath) — the paired terms of divine animating energy. Both <em>rûaḥ</em> (spirit/wind) and <em>nišmāh</em> (breath) are the source of all creaturely life (Gen 2:7; Job 33:4). If God were to withdraw his <em>rûaḥ</em> — gather it back to himself — the consequence follows in v15. The conditional <em>im-yāśîm</em> (if he were to set) is a counterfactual: God does not in fact do this continuously. But the bare possibility illuminates the full extent of creaturely dependence on divine sustenance. Life is not inherent to creatures; it is on permanent loan from God.</p>",
    "15": "<p>&#8220;All flesh would perish together, and human beings would return to dust.&#8221; <em>Yigwaʿ kol-bāśār yāḥaḏ</em> (all flesh would expire/perish together) and <em>wᵉʾāḏām ʿal-ʿāpār yāšûḇ</em> (and man would return to dust) — the reversal of Gen 2:7 and 3:19 (&#8220;you are dust and to dust you shall return&#8221;). The whole created order is ontologically dependent on God&#8217;s continued outbreathing. This is the positive form of the argument: God is not tyrannically arbitrary; God is the necessary condition for all existence. The God who sustains all life cannot be acting against the basic good of creatures. Elihu uses the cosmological argument in service of theodicy.</p>",
    "16": "<p>&#8220;If you have understanding, hear this; listen to what I am saying.&#8221; Elihu&#8217;s return to the direct imperative after the cosmological argument of vv13-15. <em>Im-bināh</em> (if you have understanding/discernment) — the <em>bināh</em> appeal is wisdom terminology (Prov 1:2; 4:5,7). He is now specifically addressing someone in the company — likely Job, who has been the implicit referent throughout ch34 despite the address to &#8220;wise men&#8221; in v2. The instruction-to-listen frame holds the speech together as pedagogical rather than judicial.</p>",
    "17": "<p>&#8220;Shall one who hates justice govern? Will you condemn the One who is righteous and mighty?&#8221; <em>Hap-śônēʾ mišpāṭ yaḥbōš</em> (shall one who hates justice bind/govern?) — the rhetorical question points to the absurdity of a justice-hating ruler. <em>ʾIm-ṣaddîq kaббîr tᵉrašîaʿ</em> (will you condemn the One who is righteous and mighty?) — Job&#8217;s position, Elihu argues, requires condemning God; but the one who is <em>ṣaddîq</em> (righteous) and <em>kabbîr</em> (mighty) cannot logically be condemned. The argument from divine character (v10-12) is now expressed as a logical impossibility: condemning a perfectly righteous ruler on the basis of one afflicted person&#8217;s complaint.</p>",
    "18": "<p>&#8220;Is it right to say to a king, &#8216;You are worthless,&#8217; and to nobles, &#8216;You are wicked&#8217;?&#8221; The argument from analogy: even human royalty should not be addressed in such terms without overwhelming evidence and proper procedure. <em>Bᵉliyyāʿal</em> (worthless, wicked, base) — the term carries its full weight: not just ineffective but morally corrupt. The logic is <em>a fortiori</em>: if this would be improper with a king, how much more so with God (cf. Eccl 10:20). Job&#8217;s accusations against God have used language appropriate to condemning a corrupt human magistrate; Elihu argues the category is wrong.</p>",
    "19": "<p>&#8220;How much less to him who shows no partiality to princes and does not favor the rich over the poor, for they are all the work of his hands?&#8221; <em>Ašer lōʾ-nāśāʾ pᵉnê śārîm</em> (who does not lift up the face of princes — show partiality) — divine impartiality is the mark of genuine justice. The rich and poor are <em>maʿᵃśēh yāḏāyw</em> (the work of his hands) — equally formed, equally dependent. God&#8217;s justice cannot be bought or influenced by status. This is simultaneously a theological argument and an implicit rebuke of the Friends: their theodicy worked to justify the wealthy righteous and condemn the suddenly poor. God does not operate on those social categories.</p>",
    "20": "<p>&#8220;In a moment they die; at midnight the people are convulsed and pass away, and the mighty are removed — without human effort.&#8221; <em>Peta</em> (in a moment, suddenly) — the sudden death that removes even the mighty. <em>Bᵉḥᵃṣî hallaylāh</em> (at midnight) — the most unexpected time, the nadir of human alertness. <em>Wᵉyᵃʿᵃḇrû wᵉyûsōr ʾabbîr lōʾ bᵉyāḏ</em> (they pass away and the mighty are removed, not by hand) — death comes to the powerful without any human agent executing it. God removes rulers directly, without intermediaries. This is the sovereignty argument in dramatic form: no human power can insulate itself from divine removal.</p>",
    "21": "<p>&#8220;For his eyes are on the ways of everyone, and he sees all their steps.&#8221; <em>Kî-ʿênāyw ʿal-darkê-ʾîš</em> (his eyes are on the ways of a man) and <em>yirʾeh kol-ṣᵃʿāḏāyw</em> (he sees all their steps) — divine omniscience as the ground of impartial justice. God cannot be deceived or manipulated because he sees everything. This is not surveillance-as-oppression (Job&#8217;s reading of 7:17-18 and 10:14) but omniscient justice: God sees what the human magistrate cannot see and therefore can judge what the human magistrate cannot judge. Elihu frames what Job experienced as hostile watching as the precondition for fair judgment.</p>",
    "22": "<p>&#8220;There is no darkness or deep shadow where evildoers can hide themselves.&#8221; <em>ʾEn-ḥōšeḵ wᵉʾên ṣalmāweṯ</em> (there is no darkness and no shadow of death) where the wicked can hide. <em>Ṣalmāweṯ</em> (shadow of death / deep darkness) — the term Job used for his own condition (10:21-22; 12:22; 16:16; 28:3). For Job, <em>ṣalmāweṯ</em> was the place of his suffering; for Elihu, it is the place where the wicked futilely seek refuge. God&#8217;s omniscient reach extends even to <em>ṣalmāweṯ</em>. This reframes Job&#8217;s darkness not as abandonment but as the place God also sees.</p>",
    "23": "<p>&#8220;For he does not impose on anyone more than is warranted to bring them before God in judgment.&#8221; <em>Lōʾ yāśîm ʿôḏ ʿal-ʾîš</em> (he does not impose further on anyone) — the point is that God&#8217;s judicial process does not exceed what the case requires. The phrase is difficult but the MKT&#8217;s rendering captures the restraint: God is not extravagant in his judgments; he uses the minimum necessary weight to bring the person before his judgment. This limits the retributive excess the Friends implicitly assumed: God does not pile on beyond what justice requires.</p>",
    "24": "<p>&#8220;He shatters the mighty without investigation and sets others in their place.&#8221; <em>Yāraʿ kabbîrîm lōʾ-ḥēqer</em> (he shatters the mighty without investigation/without limit) — the divine removal of powerful rulers happens without the need for the usual judicial procedures. <em>Wᵉyaʿᵃmēḏ ʾăḥērîm taḥtām</em> (he sets others in their place) — the replacement is sovereign and immediate. This is not arbitrary tyranny but sovereign administration: God needs no drawn-out process to remove a corrupt ruler because his omniscience (vv21-22) means he already has all the evidence.</p>",
    "25": "<p>&#8220;For he knows their deeds, and he overturns them in the night; they are crushed.&#8221; <em>Kî yāḏaʿ maʿᵃllêhem</em> (for he knows their deeds/works) — the basis of the divine overturning is knowledge. The nighttime reversal (<em>ballāylāh</em>) echoes the sudden deaths of v20: midnight is when God moves against those who have built empires of oppression. <em>Wᵉyiddakkᵉʾû</em> (they are crushed/pulverized) — the same verb used for the crushing of the wicked elsewhere in Job (4:19; 5:4). The powerful rulers are not exceptions to God&#8217;s justice; they are subject to it on an accelerated schedule due to their visibility and responsibility.</p>",
    "26": "<p>&#8220;He strikes them for their wickedness in an open place where others can see.&#8221; <em>Bᵉmaqqôm rᵉšāʿîm sᵉpāqām</em> (in the place of the wicked he strikes them) and <em>bimᵉqôm rōʾîm</em> (in a place where those who see) — the public character of divine judgment against oppressive rulers is emphasized. The judgment is not hidden; it is done where it can be witnessed, so that the lesson is available to all. This is the positive form of the argument from v25: God does not just remove rulers privately; he makes the removal visible as a teaching event for the community.</p>",
    "27": "<p>&#8220;Because they turned away from following him and gave no thought to any of his ways.&#8221; <em>ʾᵃšer ʿal-kēn sāru mēʾaḥᵃrāyw</em> (because they turned from following him) — the reason for divine judgment: apostasy in leadership. <em>Kol-dᵉrāḵāyw lōʾ hiśkîlû</em> (they did not consider any of his ways) — the failure is cognitive-volitional: they did not attend to how God orders reality. The rulers who exploit the poor (v28) do so because they have systematically ignored God&#8217;s ways. Elihu&#8217;s theodicy here answers a question Job did not ask: why do wicked rulers fall? But it also implies: Job&#8217;s suffering does not fit this category.</p>",
    "28": "<p>&#8220;So that they brought the cry of the poor before him, and he heard the outcry of the afflicted.&#8221; <em>Ṣaʿᵃqaṯ-dallîm</em> (the cry of the poor/weak) and <em>šawᵃʿaṯ ʿᵃniyyîm</em> (the outcry of the afflicted) — God hears the cry that bypasses all earthly courts. The mechanism of cosmic justice operates through the cry of the oppressed: God responds to the outcry that has no earthly advocate. This is the prophetic tradition in its purest form (Exod 22:23; Prov 21:13). Elihu&#8217;s theodicy here is at its most compelling: the poor cry, God hears, rulers fall. But this raises the question Job embodies — what about when the righteous cry and there is silence?</p>",
    "29": "<p>&#8220;When he is quiet, who can condemn? When he hides his face, who can see him?&#8221; <em>Wᵉhûʾ yašqîṭ ûmî yārešîaʿ</em> (when he is quiet, who can condemn?) — Elihu acknowledges the phenomenon of divine silence that Job has experienced. <em>Yastîr pānāyw</em> (he hides his face) is exactly Job&#8217;s complaint in 13:24. Elihu&#8217;s response: even in the hiding, God cannot be condemned, because the hiding may be purposive. The &#8220;hiding of the face&#8221; is not abandonment but a mode of divine action. This is the closest Elihu comes to addressing Job&#8217;s actual experience — but he addresses it structurally, not personally.</p>",
    "30": "<p>&#8220;Lest a godless person reign and ensnare the people.&#8221; <em>Mimmᵉlōḵ ʾāḏām ḥānēp</em> (lest a godless/profane man reign) and <em>môqᵉšê ʿām</em> (snares of the people) — the purpose of divine sovereignty: the prevention of godless rule that traps populations. God&#8217;s removal of rulers is not arbitrary; it is structurally protective of communities. The social theology here is important: Elihu understands that individual theodicy (why does Job suffer?) cannot be separated from social theodicy (why do peoples suffer under evil rulers?). Both are addressed by the same divine justice that hears the cry of the poor.</p>",
    "31": "<p>&#8220;Has anyone said to God, &#8216;I have endured my punishment; I will not sin any more&#8217;?&#8221; <em>Kî-ʾel-ʾēl ʾāmar nāśāʾtî</em> (for has he said to God: I have borne/lifted it) — the rhetorical question opens a new section (vv31-37): what is the proper human response to divine discipline? Elihu presents the ideal response: submission and reform. The confession &#8220;I have endured my punishment&#8221; (<em>nāśāʾtî</em> can mean &#8220;I have borne my chastisement&#8221;) followed by reform — &#8220;I will not sin again&#8221; — is the posture Elihu implicitly commends to Job. Job&#8217;s refusal to adopt this posture is part of what Elihu finds problematic.</p>",
    "32": "<p>&#8220;And: &#8216;Teach me what I cannot see; if I have done wrong, I will not do it again.&#8217;&#8221; <em>Hôrēnî ʾim-ʾāwen pāʿaltî lōʾ ʾōsîp</em> (teach me; if I have done wrong, I will not do it again) — the idealized response adds the petition for divine instruction alongside the commitment to reform. This is the appropriate response to the dream-disciplines and suffering-chastenings Elihu described in ch33: &#8220;show me what I cannot see.&#8221; It is notable that even Elihu&#8217;s idealized penitent is conditional — &#8220;if I have done wrong&#8221;. But the implied expectation is that investigation will reveal some fault. Elihu cannot fully escape the Friends&#8217; presupposition that suffering implies fault.</p>",
    "33": "<p>&#8220;Should he repay you on your own terms because you reject his?&#8221; <em>Hᵉmimmᵉḵā yᵉšallᵉmennāh kî-māʾastā</em> (should he repay you on your terms because you rejected his?) — Elihu challenges Job&#8217;s implicit demand that God operate on Job&#8217;s terms. The word <em>māʾastā</em> (you rejected/refused) is Elihu&#8217;s sharpest accusation in ch34: Job has rejected God&#8217;s terms. Whether this is accurate characterization of Job&#8217;s position is debatable; Job has not rejected God but has demanded accountability from God. Elihu conflates accountability-demand with rejection of God&#8217;s sovereignty, a conflation the divine speeches will not endorse.</p>",
    "34": "<p>&#8220;People of understanding will agree with me, and every wise person who hears me will say.&#8221; Elihu again appeals to the consensus of the wise (<em>ʾanšê-lēḇāḇ</em>, men of heart/understanding, and <em>ḥāḵām</em>, the wise man). This is a rhetorical closing move: before delivering the verdict (v35), Elihu frames it as what any wise person would conclude. The appeal to consensus is itself a wisdom convention — wisdom is not private but communally validated. The problem is that the verdicts of the &#8220;wise&#8221; the book has shown us (the Friends) have been wrong. Elihu&#8217;s confidence in consensus is ironically undercut by the narrative context.</p>",
    "35": "<p>&#8220;&#8216;Job speaks without knowledge; his words are without insight.&#8217;&#8221; <em>Iyyôḇ lōʾ-bᵉḏaʿaṯ yᵉḏabbēr</em> (Job speaks not with knowledge) and <em>ûḏᵉḇārāyw lōʾ bᵉhaśkēl</em> (his words are not with insight) — Elihu delivers the verdict he has prepared. <em>Ḏaʿat</em> (knowledge) and <em>haśkēl</em> (insight/discernment) are both wisdom-epistemological terms; their absence is the wisdom tradition&#8217;s most serious charge. The divine speeches will use almost identical language: &#8220;Who is this who darkens counsel by words without knowledge?&#8221; (38:2). But where Elihu&#8217;s verdict is part of a prosecution, the divine version will be transformative — leading to Job&#8217;s restoration rather than condemnation.</p>",
    "36": "<p>&#8220;Would that Job were tested to the limit, because his answers are like those of wicked men.&#8221; <em>ʾĀḇî yibbāḥēn Iyyôḇ ʿaḏ-nēṣaḥ</em> (I wish that Job were tried to the uttermost) — Elihu&#8217;s zeal tips here into something darker: a wish for maximal testing. <em>ʿal-tᵉšûḇōṯ bᵉʾanšê-ʾāwen</em> (because his answers are like those of wicked men) — the association of Job&#8217;s rhetoric with <em>ʾāwen</em> (iniquity/wickedness) is the harshest thing Elihu says. He is wrong about this: the divine verdict (42:7) will vindicate Job&#8217;s speech as more honest than the Friends&#8217; piety. Elihu&#8217;s error here is precisely what the book is designed to expose: equating theological impropriety with moral wickedness.</p>",
    "37": "<p>&#8220;For he adds rebellion to his sin; he mocks us and heaps up words against God.&#8221; <em>Yōsîp ʿal-ḥaṭṭāʾṯô pešaʿ</em> (he adds to his sin rebellion) — Elihu ends ch34 with the most severe indictment: Job&#8217;s continued speech is escalating from sin to <em>pešaʿ</em> (deliberate rebellion). <em>Bênênû yispôq</em> (he mocks/claps among us) and <em>yarbeh ʾᵃmārāyw lāʾēl</em> (he multiplies words against God). The final charge — multiplying words against God — is the opposite of Job&#8217;s actual condition: Job is pouring out suffering-speech, not blasphemy. The irony the book preserves is that God will vindicate these very &#8220;multiplied words&#8221; as more honest than Elihu&#8217;s measured theology.</p>"
  },
  "35": {
    "1": "<p>&#8220;Elihu continued and said.&#8221; The formulaic introduction marks the third of Elihu&#8217;s four speeches (chs32-33 = first; ch34 = second; ch35 = third; ch36-37 = fourth). Each speech builds on the previous while shifting angle: ch33 addressed the mediation mechanism; ch34 addressed divine justice; ch35 addresses the transcendence argument — whether human righteousness or sin affects God at all. The progression shows Elihu as a systematic theologian working through the implications of his theodicy.</p>",
    "2": "<p>&#8220;Do you think this is just when you say, &#8216;My righteousness is more than God&#8217;s&#8217;?&#8221; <em>Mišpāṭ</em> (justice/judgment/right) — the question of what is right/just. Elihu attributes to Job the claim &#8220;my righteousness is more than God&#8217;s&#8221; (<em>ṣiḏqî mēʾēl</em>). Job never said this in these words; the closest approximation is 13:18 (&#8220;I know that I will be vindicated&#8221;) and 27:2-6 (the righteousness-assertion). Elihu may be extrapolating the logical implication: if God is unjust and Job is just, then Job&#8217;s righteousness exceeds God&#8217;s justice. Whether that is a fair inference is part of the book&#8217;s ongoing argument.</p>",
    "3": "<p>&#8220;For you say, &#8216;What does it benefit you? What do I gain from not sinning?&#8217;&#8221; <em>Mah-yiskōn-lāḵ mah-ʾeoʿîl mēḥaṭṭāʾṯî</em> (what benefit is it to you? what do I gain from not sinning?) — Elihu attributes to Job a calculated cost-benefit analysis of righteousness. This echoes 21:15 (the wicked&#8217;s question: &#8220;what do we gain by praying to him?&#8221;) — Elihu is saying Job has come to reason like the wicked even if unintentionally. The question is the corruption of disinterested piety: Job&#8217;s suffering has led him to wonder whether righteousness pays, which Satan predicted from the beginning (1:9-10).</p>",
    "4": "<p>&#8220;I will give you an answer, and your companions along with you.&#8221; <em>ʾAnî ʾᵃšîḇᵉḵā millîn</em> (I will answer you with words) and <em>wᵉʾeṯ-rēʿeḵā ʿimmāḵ</em> (and your companions with you) — Elihu broadens his address: the answer he is about to give concerns not just Job but all the human companions present. The &#8220;companions&#8221; are presumably the Friends, though they have been silent since ch31. By including them in the address, Elihu signals that his transcendence argument is a universal human concern, not just Job&#8217;s private problem.</p>",
    "5": "<p>&#8220;Look up at the sky and see; behold the clouds, higher than you.&#8221; <em>Šûr-šāmayim ûrᵉʾēh</em> (look at the heavens and see) — the imperative to look upward is the beginning of Elihu&#8217;s transcendence argument. The physical gesture parallels the whirlwind speeches&#8217; invitation to observe creation (38:4, 18, 33). <em>Wᵉhabbīṭ šeḥāqîm gāḇᵉhû mimmᵉḵā</em> (look at the clouds, they are higher than you) — the incomprehensible height of the heavens above the human being is the spatial image for divine transcendence. What Job says cannot add to or subtract from God; the heavens-gap represents the ontological gap.</p>",
    "6": "<p>&#8220;If you sin, what do you accomplish against him? If your transgressions multiply, what do you do to him?&#8221; <em>Im-ḥāṭāʾtā mah-tipʿal-bô</em> (if you sin, what do you do to him?) — the transcendence argument applied to sin: human transgression does not damage God. <em>Wᵉrabbû pᵉšāʿeḵā mah-tᵃʿᵃśeh-llô</em> (and if your rebellions multiply, what do you do to him?) — the accumulation of human sin does not constitute an assault on God&#8217;s being. This is Elihu&#8217;s correction of Job&#8217;s implicit theology: Job has spoken as though his suffering constitutes an attack by God on someone who can be damaged. But the relationship runs one way ontologically — creatures can be damaged by God but not vice versa.</p>",
    "7": "<p>&#8220;If you are righteous, what do you give him? What does he receive from your hand?&#8221; <em>Im-ṣāḏaqtā mah-tittᵉn-lô</em> (if you are righteous, what do you give him?) — the flip side: human righteousness does not enrich God. <em>Mah-miyyāḏᵉḵā yiqqāḥ</em> (what does he receive from your hand?) — God cannot receive anything from human righteousness that he does not already possess. This is the OT equivalent of Rom 11:35: &#8220;who has first given to God, that God should repay him?&#8221; The argument cuts against both the Friends&#8217; theology (righteousness deserves reward) and Job&#8217;s complaint (God owes Job for his righteousness). Neither transaction is possible with the transcendent God.</p>",
    "8": "<p>&#8220;Your wickedness harms only someone like yourself, and your righteousness benefits only other people.&#8221; <em>Lāʾîš kāmôḵā rišʿeḵā</em> (your wickedness is to a man like yourself) and <em>wᵉlibeni-ʾāḏām ṣiḏqāṯeḵā</em> (and your righteousness to the sons of men) — human moral choices have human consequences, not divine ones. Sin harms the sinner and others in the human community; righteousness benefits others in the human community. God is not the recipient of either. This is both correct and limited as theology: it is true that God does not need human goodness, but Elihu&#8217;s argument risks making human moral action completely horizontal, losing the vertical dimension of covenant relationship.</p>",
    "9": "<p>&#8220;Under the weight of great oppression people cry out; they call for help from the arm of the powerful.&#8221; <em>Mērōḇ ʿᵃšûqîm yizʿāqû</em> (because of the multitude of oppressions they cry out) — the social theology of v28 in ch34 reappears. The oppressed cry; this is the normal mechanism that should activate divine justice (Exod 3:7; 22:23). But v10 will note that the cry in v9 is not directed to God. The contrast is between instinctive social-relief seeking (cry to powerful humans) and genuine theological supplication (cry to the God who made you). Elihu is setting up a critique of why some prayers go unanswered: they are cries for human assistance, not genuine address to God.</p>",
    "10": "<p>&#8220;But no one asks, &#8216;Where is God my Maker, who gives songs in the night?&#8217;&#8221; <em>ʾAyyēh ʾĕlôhay ʿōśênî</em> (where is God my Maker) — this is one of the most striking phrases in the Elihu speeches and perhaps in the book. The oppressed cry for human relief rather than seeking &#8220;God my Maker.&#8221; The personal possessive &#8220;my God&#8221; and the relational title &#8220;my Maker&#8221; frame what genuine theological address looks like. The appended phrase <em>nōṯēn zᵉmirôṯ ballāylāh</em> (who gives songs in the night) is unique: God is the source of <em>zᵉmirôṯ</em> (songs, praises) even in the nighttime of suffering. The psalms embody this capacity — to praise in the dark (Ps 42; 77; 88). This is Elihu&#8217;s most genuinely pastoral insight.</p>",
    "11": "<p>&#8220;Who teaches us more than the animals of the earth and makes us wiser than the birds of the sky?&#8221; <em>Mᵉlammᵉḏēnû mibbahmôṯ ʾāreṣ</em> (who teaches us beyond the animals of the earth) and <em>ûmēʿôp haššāmayim yᵃḥakkᵉmēnû</em> (and makes us wiser than the birds of the sky) — God&#8217;s distinctive gift to humanity over animals is wisdom. The whirlwind speeches will use animals to humble Job (the ostrich, horse, eagle in ch39), but Elihu uses them to honor humanity: God gave humans cognitive capacities animals lack. The implied argument: use those capacities to cry to God rather than to other humans. The wisdom God teaches exceeds animal instinct and should be directed Godward.</p>",
    "12": "<p>&#8220;There they cry, but he does not answer, because of the pride of evil people.&#8221; <em>Šām yiṣʿᵃqû wᵉlōʾ yᵃʿᵃneh</em> (there they cry and he does not answer) — the unanswered cry that Job has experienced and protested. Elihu&#8217;s explanation: <em>mippᵉnê gᵉʾôn rāʿîm</em> (because of the pride of evil people). The cry goes unanswered not because God is absent but because the criers are either wicked or crying to the wrong address (humans, v9) or from the wrong posture (pride). This is a partial answer to the theodicy of unanswered prayer — it identifies one category of cases (the proud/wicked who cry for relief without acknowledging God) but does not explain Job&#8217;s specific case.</p>",
    "13": "<p>&#8220;Certainly God does not hear a hollow cry; the Almighty does not regard it.&#8221; <em>ʾAḵ-šāwᵉ lōʾ-yišmaʿ ʾēl</em> (surely God does not hear a hollow/empty/vain cry) — <em>šāwᵉ</em> (vain, hollow, empty) is the same root as the third commandment (Exod 20:7: &#8220;do not take the name of the LORD in vain&#8221;) and Ps 127:1 (&#8220;in vain&#8221;). A <em>ṣᵃʿāqaṯ-šāwᵉ</em> (hollow cry) is prayer that is form without substance — religious speech that does not actually address the living God. The Almighty does not regard it because it is not genuinely addressed to him. This is Elihu&#8217;s most theologically serious critique of a certain type of prayer.</p>",
    "14": "<p>&#8220;How much less when you say you cannot see him, that the case is before him, and you must wait for him.&#8221; <em>ʾAp kî tōʾmar lōʾ tᵉšûrennû</em> (how much less when you say you cannot see him) — Elihu applies the preceding principle to Job&#8217;s specific complaint. Job has said he cannot find God to bring his case (23:3-9; 9:11). <em>Dîn lipānāyw</em> (the case/judgment before him) — this phrase concedes that Job&#8217;s case does exist before God; it is not ignored. But <em>wᵉḥôlēl lô</em> (you must wait for him) — the appropriate response to a case pending before God is waiting, not impatient accusation. Elihu is recommending the posture of lament psalms: cry, wait, trust that God hears even when silent.</p>",
    "15": "<p>&#8220;But now, because God has not punished in his anger and does not take sharp notice of every transgression.&#8221; <em>Wᵉʿattāh kî-ʾên pāqaḏ ʾappô</em> (and now, because God has not punished in his anger) — Elihu identifies what he sees as Job&#8217;s interpretive error: because God has not immediately punished Job&#8217;s accusations, Job takes this as license to continue and escalate. <em>Wᵉlōʾ-yāḏaʿ bappaš mᵉʾōḏ</em> (and does not greatly notice transgression) — divine patience is being misread as divine indifference. Job&#8217;s continued speech is trading on God&#8217;s long-suffering, not recognizing it as grace.</p>",
    "16": "<p>&#8220;So Job opens his mouth with empty words; he heaps up words without knowledge.&#8221; <em>Wᵉʾiyyôḇ hebel yipṣeh-pîhû</em> (Job opens his mouth with <em>hebel</em>) — <em>hebel</em> (breath/vapor/vanity) is Qohelet&#8217;s signature word (Eccl 1:2) but here used in its sense of &#8220;empty/vain.&#8221; Elihu&#8217;s final verdict on Job&#8217;s speeches in ch35 echoes his verdict in 34:35 (&#8220;without knowledge&#8221;). The closing charge is exactly the language the divine speeches will open with (38:2). But the context differs entirely: Elihu delivers it as judicial condemnation; God delivers it as the opening move of a transformative encounter. The same words accomplish completely different ends depending on the speaker.</p>"
  }
}

